# Your First Electron App – Hello World

Create two files:

**main.js** (main process)
```js
const { app, BrowserWindow } = require('electron');

function createWindow(){
  const win = new BrowserWindow({ width:800, height:600 });
  win.loadFile('index.html');
}

app.whenReady().then(createWindow);

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});
```

**index.html** (renderer)
```html
<!doctype html>
<html>
<head><meta charset="utf-8"><title>Hello Electron</title></head>
<body>
  <h1>Hello, Electron!</h1>
  <p>This window is rendered by Chromium.</p>
</body>
</html>
```
Add `"main": "main.js"` to `package.json` and run `npm start`. You should see a native desktop window showing the HTML page.

# Loading Local HTML, Remote URLs & Custom Protocols

**Local file** – most common:
```js
win.loadFile('src/index.html');
```

**Remote URL** – be careful with security (CSP, `webSecurity`):
```js
win.loadURL('https://app.example.com');
```

**Custom protocol** – useful for bundlers (e.g., `app://`):
```js
app.whenReady().then(() => {
  protocol.registerFileProtocol('app', (request, callback) => {
    const url = request.url.substr(6); // strip "app://"
    callback({ path: path.normalize(`${__dirname}/${url}`) });
  });
  win.loadURL('app://index.html');
});
```

When loading remote content, disable Node integration and enforce `Content‑Security‑Policy` headers.

# Menus, Application Menu & Tray Icons

Create a native menu:
```js
const { Menu } = require('electron');
const template = [
  {
    label: 'File',
    submenu: [
      { role: 'quit' }
    ]
  },
  {
    label: 'Edit',
    submenu: [
      { role: 'undo' },
      { role: 'redo' },
      { type: 'separator' },
      { role: 'copy' },
      { role: 'paste' }
    ]
  }
];
const menu = Menu.buildFromTemplate(template);
Menu.setApplicationMenu(menu);
```

**Tray (system‑level icon)**:
```js
const { Tray, nativeImage } = require('electron');
let tray = null;
app.whenReady().then(() => {
  const icon = nativeImage.createFromPath('assets/tray.png');
  tray = new Tray(icon);
  tray.setToolTip('My Electron App');
  tray.setContextMenu(Menu.buildFromTemplate([
    { label: 'Show', click: () => win.show() },
    { label: 'Quit', click: () => app.quit() }
  ]));
});
```

# Inter‑process Communication (IPC)

Electron ships two IPC modules:
* **ipcMain** – used in the **main** process.
* **ipcRenderer** – used in a **renderer** (via the preload bridge).

### Basic request/response pattern
**preload/bridge.js**
```js
const { contextBridge, ipcRenderer } = require('electron');
contextBridge.exposeInMainWorld('api', {
  getAppVersion: () => ipcRenderer.invoke('app:getVersion')
});
```
**main.js**
```js
const { ipcMain, app } = require('electron');
ipcMain.handle('app:getVersion', () => app.getVersion());
```
**renderer.js** (runs in the page)
```js
document.getElementById('ver').innerText = window.api.getAppVersion();
```

### Sending a fire‑and‑forget message
```js
// renderer
window.api.send('log', 'User clicked button');
// main
ipcMain.on('log', (e, msg) => console.log('[Renderer]', msg));
```
Use `invoke/handle` for request‑response (Promise‑based) and `send/on` for one‑way messages.

# Using Node.js APIs in the Main Process

Because the main process runs **plain Node**, you can require any built‑in or third‑party module.

### Example: File system access
```js
const fs = require('fs').promises;
async function readConfig(){
  const data = await fs.readFile(path.join(app.getPath('userData'), 'config.json'), 'utf‑8');
  return JSON.parse(data);
}
```
### Example: Child processes
```js
const { exec } = require('child_process');
exec('git --version', (err, stdout) => {
  if (err) return console.error(err);
  console.log('Git version:', stdout.trim());
});
```
### Example: Native modules
Install a library that needs compilation (e.g., `sharp` for image processing) and use it directly in the main process.
```js
const sharp = require('sharp');
sharp('input.png').resize(200).toFile('output.png');
```
Remember: **Never** expose these Node APIs directly to the renderer – always go through a preload bridge.

# File System Access – Reading & Writing

Electron provides `app.getPath(name)` to locate OS‑specific folders (`userData`, `desktop`, `documents`).
```js
const { app } = require('electron');
const dataPath = app.getPath('userData');
```
**Read a file** (async):
```js
const fs = require('fs').promises;
async function loadNotes(){
  const file = path.join(dataPath, 'notes.json');
  try {
    const raw = await fs.readFile(file, 'utf-8');
    return JSON.parse(raw);
  } catch(e){
    return [];
  }
}
```
**Write a file**:
```js
async function saveNotes(notes){
  const file = path.join(dataPath, 'notes.json');
  await fs.writeFile(file, JSON.stringify(notes, null, 2), 'utf-8');
}
```
**Show a dialog** before overwriting:
```js
const { dialog } = require('electron');
const { response } = await dialog.showMessageBox({
  type: 'question',
  buttons: ['Cancel', 'Overwrite'],
  defaultId: 1,
  title: 'Confirm',
  message: 'Overwrite existing file?'
});
if (response === 1) await saveNotes(notes);
```

# Preload Scripts & Secure Context Bridge

A **preload script** runs **before** the renderer loads any web code, in a privileged yet isolated world.
```js
// preload/bridge.js
const { contextBridge, ipcRenderer } = require('electron');

// expose a minimal, typed API
contextBridge.exposeInMainWorld('electronAPI', {
  // async request → returns a Promise
  getVersion: () => ipcRenderer.invoke('app:getVersion'),

  // fire‑and‑forget
  logMessage: (msg) => ipcRenderer.send('log', msg),

  // subscribe to events from main
  onUpdateAvailable: (callback) => ipcRenderer.on('update:available', (e, info) => callback(info))
});
```
In **main.js** you must enable the preload path:
```js
new BrowserWindow({
  webPreferences: {
    preload: path.join(__dirname, '../preload/bridge.js'),
    contextIsolation: true,
    nodeIntegration: false
  }
});
```
Now the renderer can safely call:
```js
document.getElementById('ver').innerText = await window.electronAPI.getVersion();
window.electronAPI.logMessage('App launched');
```
Never expose the full `ipcRenderer` object; only expose **specific, typed functions**.

# Native Dialogs – Open & Save Files

Electron's `dialog` module opens OS‑native file/folder pickers.
```js
const { dialog } = require('electron');

// Open a file picker (allow multiple)
async function pickFiles(){
  const { canceled, filePaths } = await dialog.showOpenDialog({
    title: 'Select a file',
    properties: ['openFile', 'multiSelections']
  });
  if (!canceled) return filePaths; // array of selected paths
}

// Save dialog
async function pickSave(){
  const { canceled, filePath } = await dialog.showSaveDialog({
    title: 'Save as',
    defaultPath: 'untitled.txt'
  });
  if (!canceled) return filePath;
}
```
You can call these functions from the **main** process or via the **preload bridge**.

# System Notifications

Electron provides the **Notification** API (same as the browser) but works in the main process and can show native OS notifications.
```js
function notify(title, body){
  new Notification({ title, body }).show();
}

notify('Download complete', 'Your file has been saved to ~/Downloads');
```
On macOS you can add `actions` (buttons) and on Windows you can set `urgency`.

If you need richer notifications (progress bar, images) use the `electron-notify` or `node-notifier` libraries.

# Bundling Renderer Code – Vite & Webpack

**Vite** (fast dev server + Rollup build) example `vite.renderer.config.js`:
```js
import { defineConfig } from 'vite';
export default defineConfig({
  root: 'src',
  build: {
    outDir: '../dist',
    emptyOutDir: true,
    rollupOptions: {
      input: 'src/index.html'
    }
  }
});
```
Run `vite` for dev, `vite build` for production.

**Webpack** example (simplified):
```js
// webpack.renderer.config.js
const path = require('path');
module.exports = {
  mode: 'production',
  entry: './src/renderer.js',
  output: { filename: 'renderer.js', path: path.resolve(__dirname, 'dist') },
  module: { rules: [{ test: /\.css$/, use: ['style-loader','css-loader'] }] }
};
```
Both tools generate a single JS bundle that you load via a `<script>` tag in `index.html`.

# State Management Across Processes

Because the UI lives in a separate renderer, you need a strategy to keep data in sync.

### Option 1: Central store in the Main process
* Store app‑wide state in a plain JavaScript object.
* Expose `getState` / `setState` via the preload bridge.
* Emit change events to renderers when the state updates.
```js
// preload/bridge.js
contextBridge.exposeInMainWorld('store', {
  get: () => ipcRenderer.invoke('store:get'),
  set: (key, value) => ipcRenderer.send('store:set', key, value),
  onChange: (cb) => ipcRenderer.on('store:changed', (e, newState) => cb(newState))
});
```

### Option 2: Use a lightweight library (e.g., **Redux**, **MobX**) inside the renderer only, and persist to disk via IPC when needed.

### Option 3: **electron-store** – a ready‑made persistent store that lives in the main process and offers a simple API.
```js
const Store = require('electron-store');
const store = new Store();
store.set('user.name', 'Bob');
console.log(store.get('user.name'));
```

# Data Persistence – electron-store, SQLite & LowDB

### electron-store (key/value JSON)
```bash
npm install electron-store
```
```js
const Store = require('electron-store');
const store = new Store();
store.set('settings.theme', 'dark');
console.log(store.get('settings.theme'));
```
Data is saved in a plain JSON file inside `app.getPath('userData')`.

### SQLite (via better‑sqlite3)
```bash
npm install better-sqlite3
```
```js
const Database = require('better-sqlite3');
const db = new Database(path.join(app.getPath('userData'), 'app.db'));
db.exec('CREATE TABLE IF NOT EXISTS notes (id INTEGER PRIMARY KEY, title TEXT, body TEXT)');
function addNote(title, body){
  const stmt = db.prepare('INSERT INTO notes (title, body) VALUES (?, ?)');
  return stmt.run(title, body).lastInsertRowid;
}
```
SQLite is great for relational data and fast queries.

### LowDB (tiny JSON database)
```bash
npm install lowdb
```
```js
const { Low, JSONFile } = require('lowdb');
const adapter = new JSONFile(path.join(app.getPath('userData'), 'db.json'));
const db = new Low(adapter);
await db.read();
db.data ||= { notes: [] };
db.data.notes.push({ id: Date.now(), text: 'Hello' });
await db.write();
```
LowDB is perfect for small prototype apps.

# Auto‑Updates with electron‑updater

**electron‑updater** (part of **electron‑builder**) abstracts away the platform‑specific update mechanisms (Squirrel on Windows, NSIS, macOS app‑store, etc.).

### Install
```bash
npm install electron-updater
```
### Basic usage in `main.js`
```js
const { autoUpdater } = require('electron-updater');

autoUpdater.checkForUpdatesAndNotify();

autoUpdater.on('update-available', info => {
  console.log('Update available', info.version);
});
autoUpdater.on('update-downloaded', info => {
  const choice = dialog.showMessageBoxSync({
    type: 'question',
    buttons: ['Later', 'Install now'],
    defaultId: 1,
    message: `Version ${info.version} downloaded. Install now?`
  });
  if (choice === 1) autoUpdater.quitAndInstall();
});
```
### Packaging for updates
* Use **electron‑builder** to create a **GitHub release** (or any server) that hosts the `*.exe`, `*.dmg`, `*.AppImage` files.
* Set the `publish` field in `package.json`:
```json
"build": {
  "publish": [{ "provider": "github", "owner": "myuser", "repo": "my‑app" }]
}
```
Now each new release is automatically detected by `autoUpdater`.

# Debugging – DevTools, Remote Debugging & Logging

### Open DevTools in a renderer window
```js
win.webContents.openDevTools({ mode: 'detach' });
```
You can also enable it only in development:
```js
if (!app.isPackaged) win.webContents.openDevTools();
```
### Remote debugging (headless CI)
Launch Electron with the `--remote-debugging-port` flag:
```bash
electron . --remote-debugging-port=9222
```
Then connect from Chrome at `http://localhost:9222`.
### Logging from the main process
```js
const log = require('electron-log');
log.info('App started');
log.error('Oops');
```
The log file is saved to `app.getPath('logs')/main.log`.
### Capture crashes
```js
app.on('render-process-gone', (event, webContents, details) => {
  log.error(`Renderer crashed: ${details.reason}`);
});
```
Use the **`electron-debug`** module for hot‑reloading shortcuts during development.

# Testing Electron Apps – Spectron & Playwright

### Spectron (official but now deprecated)
```bash
npm install --save-dev spectron mocha
```
```js
const { Application } = require('spectron');
const assert = require('assert');

describe('App launch', function(){
  this.timeout(10000);
  let app;
  beforeEach(()=>{ app = new Application({ path: require('electron'), args: ['.'] }); return app.start(); });
  afterEach(()=> app && app.stop());

  it('shows a window', async()=>{ const count = await app.client.getWindowCount(); assert.equal(count, 1); });
});
```
### Playwright (modern, cross‑platform)
```bash
npm install --save-dev @playwright/test electron
```
```js
// tests/electron.test.js
const { test, expect } = require('@playwright/test');
const { _electron: electron } = require('playwright');

test('app has title', async () => {
  const app = await electron.launch({ args: ['.'] });
  const window = await app.firstWindow();
  await expect(window).toHaveTitle(/MyApp/);
});
```
Playwright can also record videos and run headless CI.

### Unit testing the main process
Use any Node test runner (Jest, Mocha) because the main process is just a Node script.
```js
// main.test.js
const { app } = require('electron');
test('app is not null', () => { expect(app).toBeDefined(); });
```
